INSERT INTO furniture (aic_id, accession, title, classification, department, form_bucket, form_type, maker_name, maker_display, origin, place, date_display, date_begin, date_end, medium, dimensions, creditline, image_id, alt_text, collection_url) VALUES (121777, '1993.155', 'Cabinet on Stand', 'Furniture', 'Applied Arts of Europe', 'Case Piece', 'cabinet', 'Attributed to William Vile (born England, about 1700–1767)', 'Attributed to William Vile (born England, about 1700–1767); London', 'England', 'England', 'c. 1760', 1755, 1765, 'Mahogany, ebony, boxwood', '120.7 × 53.4 × 42.6 cm (47 1/2 × 21 × 16 3/4 in.)', 'Eloise W. Martin Fund; Gladys Anderson, Tillie C. Cohn, and Mary Louise Stevenson endowments', '908ba795-719f-38b2-6604-f45a9f79bab4', 'Elongated cabriole legs of carved mahogany support a cabinet veneered with mahogany and outlined by ebony mouldings. On the front panel of the cabinet the veneer is quartered and the mouldings bordered by carved rococo C-scrolls. A skirt of intricately carved scrolls, floral garlands and single blossoms frames the cabinet on three sides. This relief work and the galleried superstructure are painted, it appears, to simulate ivory.', 'https://www.artic.edu/artworks/121777');
